            var isValidEmail = await ApplicationService.ValidateEmailAsync(_email);
            if (!isValidEmail)
            {
                _errorMessage = "Please enter a valid email address.";
                return;
            }
            _currentStep = 1;
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void NextFromWorkHistory()
    {
        _errorMessage = string.Empty;

        foreach (var entry in _workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate == default)
            {
                _errorMessage = "Company name, job title, and start date are required for all positions.";
                return;
            }
        }

        _currentStep = 2;
    }

    private void NextFromReferences()
    {
        _errorMessage = string.Empty;

        foreach (var reference in _references)
        {
            if (string.IsNullOrWhiteSpace(reference.Name) || string.IsNullOrWhiteSpace(reference.Relationship) ||
