+                @if (_isValidating)
+                {
+                    <span>Validating...</span>
+                }
+                else
+                {
+                    <span>Next</span>
+                }
+            </button>
+        </div>
+    </div>
+}
+
+<!-- Step 2: Work History -->
+@if (_currentStep == 1)
+{
+    <div class="form-section">
+        <h3>Work History</h3>
+        @for (int i = 0; i < _workEntries.Count; i++)
+        {
+            var index = i;
+            <div class="card mb-3 p-3">
+                <div class="d-flex justify-content-between align-items-center mb-2">
+                    <h5>Position @(index + 1)</h5>
+                    @if (_workEntries.Count > 1)
+                    {
+                        <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveWorkEntry(index)">Remove</button>
+                    }
+                </div>
+                <div class="mb-3">
+                    <label class="form-label">Company Name *</label>
+                    <input type="text" class="form-control" @bind="_workEntries[index].Company" />
+                </div>
+                <div class="mb-3">
+                    <label class="form-label">Job Title *</label>
+                    <input type="text" class="form-control" @bind="_workEntries[index].Title" />
+                </div>
+                <div class="row mb-3">
+                    <div class="col-md-6">
+                        <label class="form-label">Start Date *</label>
+                        <input type="date" class="form-control" @bind="_workEntries[index].StartDate" />
+                    </div>
+                    <div class="col-md-6">
+                        <label class="form-label">End Date</label>
+                        <input type="date" class="form-control" @bind="_workEntries[index].EndDate" disabled="@_workEntries[index].IsCurrent" />
+                        <div class="form-check mt-1">
+                            <input type="checkbox" class="form-check-input" id="current-@index" @bind="_workEntries[index].IsCurrent" />
+                            <label class="form-check-label" for="current-@index">Currently working here</label>
+                        </div>
+                    </div>
+                </div>
+                <div class="mb-3">
+                    <label class="form-label">Description</label>
+                    <textarea class="form-control" rows="3" @bind="_workEntries[index].Description"></textarea>
+                </div>
+            </div>
+        }
+        <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
+        </div>
+    </div>
+}
+
+<!-- Step 3: References -->
+@if (_currentStep == 2)
+{
+    <div class="form-section">
+        <h3>References</h3>
+        @for (int i = 0; i < _references.Count; i++)
+        {
+            var index = i;
+            <div class="card mb-3 p-3">
+                <div class="d-flex justify-content-between align-items-center mb-2">
+                    <h5>Reference @(index + 1)</h5>
+                    @if (_references.Count > 2)
+                    {
+                        <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveReference(index)">Remove</button>
+                    }
+                </div>
+                <div class="mb-3">
+                    <label class="form-label">Name *</label>
+                    <input type="text" class="form-control" @bind="_references[index].Name" />
+                </div>
+                <div class="mb-3">
+                    <label class="form-label">Relationship *</label>
+                    <input type="text" class="form-control" @bind="_references[index].Relationship" />
+                </div>
+                <div class="row mb-3">
+                    <div class="col-md-6">
+                        <label class="form-label">Email *</label>
+                        <input type="email" class="form-control" @bind="_references[index].Email" />
+                    </div>
+                    <div class="col-md-6">
+                        <label class="form-label">Phone *</label>
+                        <input type="tel" class="form-control" @bind="_references[index].Phone" />
+                    </div>
+                </div>
+            </div>
+        }
+        @if (_references.Count < 3)
+        {
+            <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
+        }
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
+        </div>
+    </div>
+}
+
+<!-- Step 4: Cover Letter -->
+@if (_currentStep == 3)
+{
+    <div class="form-section">
+        <h3>Cover Letter</h3>
+        <div class="mb-3">
+            <textarea class="form-control" rows="12" @bind="_coverLetter" @bind:event="oninput" maxlength="2000"></textarea>
+            <div class="text-muted mt-1">@_coverLetter.Length / 2000 characters</div>
+        </div>
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
+        </div>
+    </div>
+}
+
+<!-- Step 5: Review & Submit -->
+@if (_currentStep == 4)
+{
+    @if (_submitted)
+    {
+        <div class="form-section text-center">
+            <h3 class="text-success">Application Submitted!</h3>
+            <p>Your application has been submitted successfully.</p>
+            <p><strong>Application ID: @_applicationId</strong></p>
+        </div>
+    }
+    else
+    {
+        <div class="form-section">
+            <h3>Review & Submit</h3>
+
+            <!-- Personal Info Summary -->
+            <div class="review-section">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>Personal Information</h5>
+                    <a href="#" @onclick="() => GoToStep(0)" @onclick:preventDefault>Edit</a>
+                </div>
+                <dl class="row">
+                    <dt class="col-sm-3">Full Name</dt>
+                    <dd class="col-sm-9">@_fullName</dd>
+                    <dt class="col-sm-3">Email</dt>
+                    <dd class="col-sm-9">@_email</dd>
+                    <dt class="col-sm-3">Phone</dt>
+                    <dd class="col-sm-9">@_phone</dd>
+                    <dt class="col-sm-3">Address</dt>
+                    <dd class="col-sm-9">@_address</dd>
+                </dl>
+            </div>
+
+            <!-- Work History Summary -->
+            <div class="review-section">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>Work History</h5>
+                    <a href="#" @onclick="() => GoToStep(1)" @onclick:preventDefault>Edit</a>
+                </div>
+                @foreach (var entry in _workEntries)
+                {
+                    <div class="mb-2 ps-3 border-start">
+                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
+                        <small class="text-muted">
+                            @entry.StartDate.ToString("MMM yyyy") &mdash;
+                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
+                        </small>
+                        @if (!string.IsNullOrWhiteSpace(entry.Description))
+                        {
+                            <p class="mb-0 mt-1">@entry.Description</p>
+                        }
+                    </div>
+                }
+            </div>
+
+            <!-- References Summary -->
+            <div class="review-section">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>References</h5>
+                    <a href="#" @onclick="() => GoToStep(2)" @onclick:preventDefault>Edit</a>
+                </div>
+                @foreach (var reference in _references)
+                {
+                    <div class="mb-2 ps-3 border-start">
+                        <strong>@reference.Name</strong> (@reference.Relationship)<br />
+                        <small>@reference.Email &bull; @reference.Phone</small>
+                    </div>
+                }
+            </div>
+
+            <!-- Cover Letter Summary -->
+            <div class="review-section">
+                <div class="d-flex justify-content-between align-items-center">
+                    <h5>Cover Letter</h5>
+                    <a href="#" @onclick="() => GoToStep(3)" @onclick:preventDefault>Edit</a>
+                </div>
+                <p style="white-space: pre-wrap;">@_coverLetter</p>
+            </div>
+
+            <div class="d-flex justify-content-between">
+                <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+                <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@_isSubmitting">
+                    @if (_isSubmitting)
+                    {
+                        <span>Submitting...</span>
+                    }
+                    else
+                    {
+                        <span>Submit Application</span>
+                    }
+                </button>
+            </div>
+        </div>
+    }
+}
+
+@code {
+    private static readonly string[] _stepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
+    private int _currentStep = 0;
+    private string _errorMessage = string.Empty;
+    private bool _isValidating;
+    private bool _isSubmitting;
+    private bool _submitted;
+    private int _applicationId;
+
+    // Step 1: Personal Info
+    private string _fullName = string.Empty;
+    private string _email = string.Empty;
+    private string _phone = string.Empty;
+    private string _address = string.Empty;
+
+    // Step 2: Work History
+    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };
+
+    // Step 3: References
+    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };
+
+    // Step 4: Cover Letter
+    private string _coverLetter = string.Empty;
+
+    private string GetStepClass(int step)
+    {
+        if (step == _currentStep) return "active";
+        if (step < _currentStep) return "completed";
+        return "future";
+    }
+
+    private void GoToStep(int step)
+    {
+        if (step < _currentStep)
+        {
+            _currentStep = step;
+            _errorMessage = string.Empty;
+        }
+    }
+
+    private async Task NextFromPersonalInfo()
+    {
+        _errorMessage = string.Empty;
+
+        if (string.IsNullOrWhiteSpace(_fullName) || string.IsNullOrWhiteSpace(_email) ||
+            string.IsNullOrWhiteSpace(_phone) || string.IsNullOrWhiteSpace(_address))
+        {
+            _errorMessage = "All fields are required.";
+            return;
+        }
+
+        _isValidating = true;
+        try
+        {
+            var isValidEmail = await ApplicationService.ValidateEmailAsync(_email);
+            if (!isValidEmail)
+            {
+                _errorMessage = "Please enter a valid email address.";
+                return;
+            }
+            _currentStep = 1;
+        }
+        finally
+        {
+            _isValidating = false;
+        }
+    }
+
+    private void NextFromWorkHistory()
+    {
+        _errorMessage = string.Empty;
+
+        foreach (var entry in _workEntries)
+        {
+            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
+                entry.StartDate == default)
+            {
+                _errorMessage = "Company name, job title, and start date are required for all positions.";
+                return;
+            }
+        }
+
+        _currentStep = 2;
+    }
+
+    private void NextFromReferences()
+    {
+        _errorMessage = string.Empty;
+
+        foreach (var reference in _references)
+        {
+            if (string.IsNullOrWhiteSpace(reference.Name) || string.IsNullOrWhiteSpace(reference.Relationship) ||
+                string.IsNullOrWhiteSpace(reference.Email) || string.IsNullOrWhiteSpace(reference.Phone))
+            {
+                _errorMessage = "All fields are required for each reference.";
+                return;
+            }
+        }
+
+        _currentStep = 3;
+    }
+
+    private void NextFromCoverLetter()
+    {
+        _errorMessage = string.Empty;
+        _currentStep = 4;
+    }
+
+    private void PreviousStep()
+    {
+        _errorMessage = string.Empty;
+        if (_currentStep > 0)
+            _currentStep--;
+    }
+
+    private void AddWorkEntry()
+    {
+        _workEntries.Add(new WorkEntryModel());
+    }
+
+    private void RemoveWorkEntry(int index)
+    {
+        if (_workEntries.Count > 1)
+            _workEntries.RemoveAt(index);
+    }
+
+    private void AddReference()
+    {
+        if (_references.Count < 3)
+            _references.Add(new ReferenceModel());
+    }
+
+    private void RemoveReference(int index)
+    {
+        if (_references.Count > 2)
+            _references.RemoveAt(index);
+    }
+
+    private async Task SubmitApplication()
+    {
+        _isSubmitting = true;
+        _errorMessage = string.Empty;
+
+        try
+        {
+            var personal = new PersonalInfo(_fullName, _email, _phone, _address);
+            var workHistory = new WorkHistory(_workEntries.Select(e =>
+                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description ?? string.Empty)
+            ).ToList());
+            var references = _references.Select(r =>
+                new Reference(r.Name, r.Relationship, r.Email, r.Phone)
+            ).ToList();
+
+            var application = new JobApplication(personal, workHistory, references, _coverLetter);
+            _applicationId = await ApplicationService.SubmitApplicationAsync(application);
+            _submitted = true;
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Submission failed: {ex.Message}";
+        }
+        finally
+        {
+            _isSubmitting = false;
+        }
+    }
+
+    private class WorkEntryModel
+    {
+        public string Company { get; set; } = string.Empty;
+        public string Title { get; set; } = string.Empty;
+        public DateTime StartDate { get; set; }
+        public DateTime? EndDate { get; set; }
+        public bool IsCurrent { get; set; }
+        public string? Description { get; set; }
+    }
+
+    private class ReferenceModel
+    {
+        public string Name { get; set; } = string.Empty;
+        public string Relationship { get; set; } = string.Empty;
+        public string Email { get; set; } = string.Empty;
+        public string Phone { get; set; } = string.Empty;
+    }
+}
+

